(window.webpackJsonp=window.webpackJsonp||[]).push([[19],{367:function(v,_,t){"use strict";t.r(_);var n=t(4),p=Object(n.a)({},(function(){var v=this,_=v.$createElement,t=v._self._c||_;return t("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[t("h1",{attrs:{id:"размышnение-о-судьбе"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#размышnение-о-судьбе"}},[v._v("#")]),v._v(" Размышление о судьбе")]),v._v(" "),t("p",[v._v("Это размышление было навеяно популярной тенденцией говорить – что измениться легко, что позорно быть дном, и прочих осуждений.\nЯ не становлюсь на сторону защиты людей находящихся на социальном дне или испытывающих затруднения в самореализации, но я и не приемлю принебрежительного к ним отношения. Здесь я изложу свой взгляд на то как функционирует общество, это крайне поверхностное рассуждение и оно не претендует на полноту или истинность, но это мой взгляд.")]),v._v(" "),t("p",[v._v("Ежедневно каждый человек совершает различные поступки, не будем сейчас задаваться классификацией их на хорошие и плохие, нам достаточно знать что они совершаются.")]),v._v(" "),t("p",[v._v("Совершить поступок или нет в свою очередь определяется выбором, который каждый из нас делает осознанно или легкомысленно.")]),v._v(" "),t("p",[v._v("В этом месте я процитирую некогда популярную в интернете пословицу:\n— Посеешь поступок – пожнёшь характер,\nПосеешь характер – пожнёшь судьбу.")]),v._v(" "),t("p",[v._v("Здесь добавить нечего: поступки определяют наш характер, так например хроническое забивание болта приводит к формированию безотвественности, а привычка, что кто-то сделает за нас выбор – приводит к инфантильности. В свою очередь безответсвенность и инфатильность прямым образом определяют то, каким именно образом сложиться наша дальнейшая жизнь.")]),v._v(" "),t("p",[v._v("Вернёмся теперь к выбору – как я уже сказал он может быть осознанным или легкомысленным, но на самом деле есть третий вариант – неосознанный. К сожалению или радости, физиологически любой наш выбор является предопределённым и в какой-то степени его можно назвать неосознанным.\nДля того, чтобы так считать у меня есть две причины: нейробиология и детерминизм.")]),v._v(" "),t("p",[v._v("Детерменизм выражается в том, что каждая цепочка событий может определить события последующие за ней, и случиться могут только эти события и никакие другие; иными словами теперешние события являются прямым следствием предпосылок.")]),v._v(" "),t("p",[v._v("Это ли не судьба? Череда событий, которые определяют наше бытиё из событий случившихся в прошлом. И эта зависимости в самом деле крайне глубокая и в известном смысле её можно протянуть до самого первого человека.")]),v._v(" "),t("p",[v._v("Нейробиологически – вы не сможете совершить выбор или поступок, который бы не вписывался в поле “разрешённых событий”, созданное химией в вашей нервной системе. Но так же есть и другие чисто биологические причины: взрослому мозгу тяжелее учиться, новый опыт приводит к изнашиванию нейронных систем.")]),v._v(" "),t("p",[v._v("Эти ограничения так же означают, что человека в полной мере можно назвать машиной (другие поводы я надеюсь привести в последующих размышлениях).\nЕсли вы внимательно понаблюдаете за людьми – вы заметите, что они довольно шаблонны и при должной сноровке вы сможете предсказывать их поведение и даже речь. Примерно так и работают сложные маркетинговые системы – наши действия и желания предсказываются исходя из нашего опыта.")]),v._v(" "),t("p",[v._v("Здесь мне видится следующая деталь – жизнь человека и его возможности к самореализации определяются не только самим человеком (отбросим очевидные вещи и выделим менее очевидные):")]),v._v(" "),t("ul",[t("li",[v._v("Всё сильно зависит от “духа эпохи” – господствующих в обществе взглядов, норм, и т.д.")]),v._v(" "),t("li",[v._v("Соответствие самого человека “духу эпохи”")]),v._v(" "),t("li",[v._v("Биологические особенности человека, в первую очередь влияющие на способность адаптироваться")]),v._v(" "),t("li",[v._v("Пережитый человеком опыт")]),v._v(" "),t("li",[v._v("Etc")])]),v._v(" "),t("p",[v._v("При этом сам дух эпохи зависит от живущих людей, ведь каждый человек однажды делает выбор и совершает поступок, который в свою очередь косвенно или на прямую влияет на жизнь других людей.")]),v._v(" "),t("p",[v._v("В итоге получается сложно организованная система, что-то на подобии ансамбля, -- жизнь каждого человека определяет жизнь каждого человека, и не только живущего и будущего жить в будущем.\nДаже наше бездействие может стоить больших проблем в будущем – кто знает, может это именно вы могли бы открыть или способствовать открытию лекарства от чумы века?")]),v._v(" "),t("p",[v._v("Таким образом, я считаю что под определение слова “судьба” должна попасть именно детерменированная цепочка событий, служащая причинной настоящей жизненной ситуации.")]),v._v(" "),t("p",[v._v("Можно ли изменить эту самую судьбу и насколько она предопределенна?")]),v._v(" "),t("p",[v._v("Я считаю что она предопределенна полностью, но только в каждый момент времени – один наш поступок может запросто “загнуть линию судьбы в другое направление”, но сможем ли мы сделать этот поступок или нет – зависит от самой же нашей судьбы.")]),v._v(" "),t("p",[v._v("Человека, который может всё (более или менее) время концентрировать своё внимание на происходящих событиях, анализировать “линию судьбы” и вносить в ней изменения, проявляя недюжую силу воли и самоконтроль, я бы в полной мере назвал сверх машиной.\nТолько сверх машина может выйти за границы предопределённого.")])])}),[],!1,null,null,null);_.default=p.exports}}]);